script:
(function() {
    "use strict";

    function updateWorkspaceDynamicData() {
        try {
            // سحب البيانات الفعلية من جلسة المستخدم في ERPNext
            if (window.frappe && frappe.session) {
                // اسم المستخدم بالكامل
                const userFullName = frappe.session.user_fullname || "مستخدم نظام آرم";
                const nameElement = document.getElementById('arm-user-fullname');
                if (nameElement) {
                    nameElement.innerText = userFullName;
                }
            }

            // تحديث الوقت والتحية
            const now = new Date();
            const hour = now.getHours();
            const greetingLabel = document.getElementById('arm-greeting-label');

            if (greetingLabel) {
                greetingLabel.innerText = (hour < 12) ? 'صباح الخير' : 'مساء الخير';
            }

            // تحديث التاريخ بصيغة ليبيا/العربية
            const dateDisplay = document.getElementById('arm-current-date');
            if (dateDisplay) {
                const options = { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' };
                dateDisplay.innerText = now.toLocaleDateString('ar-LY', options);
            }
        } catch (e) {
            console.warn("ERPNext Data Sync in progress...");
        }
    }

    // التنفيذ الفوري
    updateWorkspaceDynamicData();

    // محاولات دورية لضمان جلب الاسم فور اكتمال تحميل كائن frappe
    [500, 1500, 4000].forEach(delay => {
        setTimeout(updateWorkspaceDynamicData, delay);
    });
})();

style:
/* الأنماط المحدثة - الإصدار الثالث */
#arm-custom-dashboard-wrapper {
    font-family: 'TajawalLocal', 'Tajawal', Arial, sans-serif !important;
    padding: 15px;
    direction: rtl !important;
    text-align: right !important;
}

.arm-card {
    position: relative;
    overflow: hidden;
    background: #ffffff;
    border: 1px solid #e5e7eb;
    box-shadow: 0 10px 30px -5px rgba(0, 0, 0, 0.05);
    border-radius: 24px;
    padding: 40px 45px;
    z-index: 1;
}

.arm-card-top-bar {
    position: absolute;
    top: 0; right: 0; width: 100%; height: 6px;
    background: linear-gradient(to left, #1e293b 0%, #3b82f6 100%);
    z-index: 5;
}

/* التخطيط الهندسي المحسن - تم رفع الوضوح قليلاً (0.08) لضمان ظهوره */
.arm-geometric-grid {
    position: absolute;
    inset: 0;
    opacity: 0.40; 
    pointer-events: none;
    z-index: 0;
    background-image: 
        radial-gradient(#1e293b 0.8px, transparent 0.8px),
        linear-gradient(rgba(30, 41, 59, 0.15) 1px, transparent 1px),
        linear-gradient(90deg, rgba(30, 41, 59, 0.15) 1px, transparent 1px);
    background-size: 25px 25px, 50px 50px, 50px 50px;
}

.arm-card-inner {
    position: relative;
    z-index: 3;
    display: flex;
    flex-direction: row;
    align-items: center;
    gap: 45px;
}

/* تكبير الشعار داخل الحاوية */
.arm-logo-wrap {
    flex-shrink: 0;
    width: 190px;
    height: 190px;
    background: #ffffff;
    border-radius: 20px;
    box-shadow: 0 8px 25px rgba(0,0,0,0.05);
    border: 1px solid #f1f5f9;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 10px; /* تقليل التباعد الداخلي ليكبر الشعار */
    overflow: hidden;
}

.arm-main-logo {
    width: 92% !important; /* تكبير حدود الصورة بحد ذاتها */
    height: 92% !important;
    object-fit: contain;
    transition: transform 0.3s ease;
}

.arm-logo-wrap:hover .arm-main-logo {
    transform: scale(1.05);
}

/* تجميل العناصر النصية */
.arm-welcome-badge {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 5px 15px;
    background: #1e293b;
    color: #ffffff;
    border-radius: 50px;
    font-size: 13px;
    font-weight: 700;
    margin-bottom: 12px;
}

.arm-status-dot {
    width: 8px; height: 8px;
    border-radius: 50%; background: #60a5fa;
    animation: arm-pulse 2s infinite ease-in-out;
}

@keyframes arm-pulse {
    0%, 100% { transform: scale(1); opacity: 1; }
    50% { transform: scale(1.4); opacity: 0.5; }
}

.arm-title {
    font-size: 34px;
    font-weight: 800; color: #0f172a; margin: 0 0 10px 0;
    border: none !important;
}

.arm-subtitle {
    font-size: 16px;
    font-weight: 400; color: #64748b; line-height: 1.6;
    max-width: 520px; margin: 0 0 25px 0;
}

/* إبراز اسم المستخدم */
.arm-user-highlight {
    background: rgba(59, 130, 246, 0.08);
    padding: 10px 18px;
    border-radius: 12px;
    border-right: 4px solid #3b82f6;
}

.arm-meta-container {
    display: flex; gap: 25px; align-items: center;
}

.arm-label {
    font-size: 10px; font-weight: 600; color: #94a3b8;
    margin-bottom: 2px; display: block;
}

.arm-value-bold {
    font-size: 16px; font-weight: 800; color: #1e293b;
}

.arm-value {
    font-size: 14px; font-weight: 700; color: #475569;
}

/* شبكة الأزرار السفلية */
.arm-actions-grid {
    display: grid; grid-template-columns: repeat(4, 1fr);
    gap: 15px; margin-top: 25px;
}

.arm-btn {
    display: flex; flex-direction: column; align-items: center;
    padding: 18px 10px; background: #ffffff;
    border: 1px solid #e5e7eb; border-radius: 18px;
    transition: all 0.3s ease;
    text-decoration: none !important;
    cursor: pointer;
}

.arm-btn-icon {
    width: 52px; height: 52px;
    border-radius: 12px; background: #f8fafc;
    display: flex; align-items: center; justify-content: center;
    color: #475569; margin-bottom: 10px;
}

.arm-btn:hover {
    border-color: #3b82f6; transform: translateY(-4px);
    box-shadow: 0 8px 20px -10px rgba(59, 130, 246, 0.25);
}

.arm-btn:hover .arm-btn-icon {
    background: #1e293b; color: #ffffff;
}

.arm-btn-text {
    font-size: 13px; font-weight: 700; color: #334155;
}

@media (max-width: 850px) {
    .arm-card-inner { flex-direction: column; text-align: center; }
    .arm-actions-grid { grid-template-columns: repeat(2, 1fr); }
    .arm-user-highlight { border-right: none; border-top: 4px solid #3b82f6; }
}
